blocks.body:
{
    "level": "A2–B1",
    "intro": "]W tym rozdziale nauczysz się <strong>rozróżniać główne sposoby mówienia o przyszłości</strong> i wybierać formę w zależności od znaczenie.",
    "rules": [
        {
            "label": "BĘDZIE",
            "color": "blue",
            "text": "Spontaniczne decyzje, obietnice, prośby, neutralne przewidywania:",
            "example": "Pomogę Ci. / Myślę, że będzie padać."
        },
        {
            "label": "JEDŹ DO",
            "color": "emerald",
            "text": "Plany i prognozy oparte na tym, co widać teraz:",
            "example": "Zadzwonię do niej. Spójrz na te chmury! znaczenia:"
        },
        {
            "label": "KEY IDEA",
            "color": "amber",
            "text": "Питай себе: це рішення зараз, уже готовий план чи висновок із доказу?",
            "example": "moment now / plan before / evidence now"
        }
    ]
}

{
    "title": "Що входить у розділ",
    "intro": "Майбутні форми покривають кілька типових значень:",
    "rows": [
        {
            "en": "Czy",
            "ua": "spontaniczna decyzja, obietnica, opinia",
            "note": "Odpowiem. / Myślę, że przybędzie. deszcz."
        },
        {
            "en": "Be going to",
            "ua": "намір або план, що вже існує",
            "note": "We're going to move house."
        },
        {
            "en": "Be going to",
            "ua": "передбачення на основі доказу",
            "note": "It's going to rain."
        },
        {
            "en": "Wybór formy",
            "ua": "wybór zależy od znaczenia, a nie tylko czasu",
            "note": "ten sam pomysł na przyszłość, inny powód"
        }
    ],
    "warning": "💡 W przyszłych formularzach ważne jest nie tylko „kiedy?”, ale także „dlaczego właśnie ta forma?”."
}

{
    "title": "Na co zwrócić uwagę",
    "items": [
        "Jeśli decyzja zapadła <strong>w tej chwili</strong>, zazwyczaj wybieramy <strong>będzie</strong>.",
        "Jeśli plan był <strong>przed momentem wypowiedzi</strong>, zwykle wybieramy <strong>będziemy</strong>.",
        "Jeśli jest to <strong>opinia lub założenie</strong> bez bezpośrednich dowodów, często używamy słowa <strong>will</strong>.",
        "Jeśli obecnie istnieją <strong>widoczne dowody</strong>, często używamy słowa <strong>będziemy</strong>."
    ]
}
